# Deobfuscated Code & Explanation

## Deobfuscated Version

```javascript
var TWO_PI = Math.PI * 2;

// Configuration constants
var config = {
  repulsionK: 4000,
  springK: 0.004,
  damping: 0.92,
  gravity: 0.0003,
  particleMax: 40,
  particleFade: 0.04,
  cameraEase: 0.06
};

// Define nodes (graph vertices)
var nodes = [
  { id: "center",   label: "Hub",       r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",    label: "Alpha",     r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",     label: "Beta",      r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",    label: "Gamma",     r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",    label: "Delta",     r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon",  label: "Epsilon",   r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Define edges (springs connecting nodes)
var edges = [
  { a: "center", b: "alpha",   rest: 160, k: 0.006 },
  { a: "center", b: "beta",    rest: 160, k: 0.005 },
  { a: "center", b: "gamma",   rest: 170, k: 0.004 },
  { a: "center", b: "delta",   rest: 170, k: 0.004 },
  { a: "center", b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha",  b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma",  b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha",  b: "epsilon", rest: 200, k: 0.002 }
];

// Camera state
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particles array and frame counter
var particles = [];
var frameCount = 0;

// Find a node by its ID
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// Physics simulation step
function simulatePhysics() {
  // 1. Repulsion between all node pairs (Coulomb-like force)
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.repulsionK / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2. Spring attraction along edges (Hooke's law)
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;
    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || config.springK) * displacement;
    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3. Apply damping, gravity toward center (400,300), and update positions
  for (var n = 0; n < nodes.length; n++) {
    nodes[n].vx += (400 - nodes[n].x) * config.gravity;
    nodes[n].vy += (300 - nodes[n].y) * config.gravity;
    nodes[n].vx *= config.damping;
    nodes[n].vy *= config.damping;
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

// Spawn a particle from a random node
function spawnParticle() {
  if (particles.length >= config.particleMax) return;
  var node = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TWO_PI;
  var speed = 0.3 + Math.random() * 0.7;
  particles.push({
    x: node.x,
    y: node.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * 1.2
  });
}

// Update all particles
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    p.vx *= 0.995;
    p.vy *= 0.995;
    p.x += p.vx;
    p.y += p.vy;
    p.age++;
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

// Smoothly interpolate camera toward target
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.cameraEase;
  camera.y += (cameraTarget.y - camera.y) * config.cameraEase;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.cameraEase;
}

// Main tick function
function tick() {
  simulatePhysics();
  updateCamera();
  if (frameCount % 3 === 0) spawnParticle();
  updateParticles();
  frameCount++;
}

setInterval(tick, 16); // ~60 FPS
```

## What It Does

This is a **force-directed graph simulation** — the same kind of physics engine used to visualize network diagrams. Here's the breakdown:

### 🔵 Nodes (6 total)
A central **"Hub"** node connected to 5 satellite nodes (Alpha, Beta, Gamma, Delta, Epsilon), each with a radius and position.

### 🔗 Edges (8 springs)
Connections between nodes act as **springs** (Hooke's law). Each has a rest length and stiffness constant `k`.

### ⚡ Physics Engine (runs every ~16ms)
1. **Repulsion** — All nodes repel each other (like charged particles — Coulomb's law), preventing overlap
2. **Spring attraction** — Connected nodes are pulled toward their rest distance
3. **Gravity** — Gentle centering force pulls everything toward (400, 300)
4. **Damping** — Velocity is multiplied by 0.92 each frame to prevent runaway oscillation

### ✨ Particles
Every 3 frames, a decorative particle spawns from a random node, drifts outward with friction, and dies after a random lifespan — purely cosmetic ambient effect.

### 🎥 Camera
Smoothly eases toward a target position/zoom using linear interpolation (lerp).

> **In short:** This is the **backend physics simulation** for an animated, interactive node-graph visualization (like a mind map or network topology), complete with ambient floating particles and a smooth camera. It's missing only the rendering/drawing code (likely a separate Canvas/WebGL draw loop).
